function BaseIcon({ children, className, viewBox }) {
  return (
    <svg
      aria-hidden="true"
      viewBox={viewBox || "0 0 16 16"}
      fill="none" 
      xmlns="http://www.w3.org/2000/svg"
      className={className || " "}
    >
      {children}
    </svg>
  );
}



